import tiktoken from typing import List, Dict
class FixedSizeChunker: def __init__(self, chunk_size: int = 500, overlap: int = 50): self.chunk_size = chunk_size self.overlap = overlap self.tokenizer = tiktoken.get_encoding("cl100k_base")
def chunk(self, text: str) -> List[Dict]: tokens = self.tokenizer.encode(text) chunks = [] start = 0 chunk_id = 0 while start < len(tokens): end = start + self.chunk_size chunk_tokens = tokens[start:end] chunk_text = self.tokenizer.decode(chunk_tokens) chunks.append({ "id": chunk_id, "text": chunk_text, "start_token": start, "end_token": min(end, len(tokens)), "token_count": len(chunk_tokens) }) start = end - self.overlap chunk_id += 1 return chunks

import nltk
from typing import List, Dict

nltk.download('punkt', quiet=True)

class SentenceChunker:
    def __init__(self, max_chunk_size: int = 500, min_chunk_size: int = 100):
        self.max_chunk_size = max_chunk_size
        self.min_chunk_size = min_chunk_size

    def chunk(self, text: str) -> List[Dict]:
        sentences = nltk.sent_tokenize(text)
        chunks = []
        current_chunk = []
        current_size = 0
        for sentence in sentences:
            sentence_size = len(sentence.split())
            if current_size + sentence_size <= self.max_chunk_size:
                current_chunk.append(sentence)
                current_size += sentence_size
            else:
                if current_size >= self.min_chunk_size:
                    chunks.append({
                        "text": " ".join(current_chunk),
                        "sentence_count": len(current_chunk),
                        "word_count": current_size
                    })
                current_chunk = [sentence]
                current_size = sentence_size
        if current_chunk:
            chunks.append({
                "text": " ".join(current_chunk),
                "sentence_count": len(current_chunk),
                "word_count": current_size
            })
        return chunks

import re
from typing import List, Dict

class ParagraphChunker:
    def __init__(self, max_chunk_size: int = 1000, min_chunk_size: int = 200):
        self.max_chunk_size = max_chunk_size
        self.min_chunk_size = min_chunk_size

    def chunk(self, text: str) -> List[Dict]:
        paragraphs = re.split(r'\n\s*\n', text)
        paragraphs = [p.strip() for p in paragraphs if p.strip()]
        chunks = []
        current_chunk = []
        current_size = 0
        for para in paragraphs:
            para_size = len(para.split())
            if para_size > self.max_chunk_size:
                if current_chunk:
                    chunks.append({
                        "text": "\n\n".join(current_chunk),
                        "paragraph_count": len(current_chunk)
                    })
                    current_chunk = []
                    current_size = 0
                sub_chunks = self._split_large_paragraph(para)
                chunks.extend(sub_chunks)
                continue
            if current_size + para_size <= self.max_chunk_size:
                current_chunk.append(para)
                current_size += para_size
            else:
                if current_size >= self.min_chunk_size:
                    chunks.append({
                        "text": "\n\n".join(current_chunk),
                        "paragraph_count": len(current_chunk)
                    })
                current_chunk = [para]
                current_size = para_size
        if current_chunk:
            chunks.append({
                "text": "\n\n".join(current_chunk),
                "paragraph_count": len(current_chunk)
            })
        return chunks

    def _split_large_paragraph(self, para: str) -> List[Dict]:
        import nltk
        sentences = nltk.sent_tokenize(para)
        chunks = []
        current = []
        current_size = 0
        for sent in sentences:
            sent_size = len(sent.split())
            if current_size + sent_size <= self.max_chunk_size:
                current.append(sent)
                current_size += sent_size
            else:
                if current:
                    chunks.append({"text": " ".join(current), "paragraph_count": 1})
                current = [sent]
                current_size = sent_size
        if current:
            chunks.append({"text": " ".join(current), "paragraph_count": 1})
        return chunks

from typing import List, Dict, Optional

class RecursiveChunker:
    def __init__(self, chunk_size: int = 500, chunk_overlap: int = 50,
                 separators: Optional[List[str]] = None):
        self.chunk_size = chunk_size
        self.chunk_overlap = chunk_overlap
        self.separators = separators or ["\n\n", "\n", ". ", " ", ""]

    def chunk(self, text: str) -> List[Dict]:
        return self._split_text(text, self.separators)

    def _split_text(self, text: str, separators: List[str]) -> List[Dict]:
        final_chunks = []
        separator = separators[0]
        splits = text.split(separator) if separator else list(text)
        current_doc = []
        current_length = 0
        for split in splits:
            split_length = len(split)
            if current_length + split_length <= self.chunk_size:
                current_doc.append(split)
                current_length += split_length + len(separator)
            else:
                if current_doc:
                    doc = separator.join(current_doc)
                    if len(doc) > self.chunk_size and len(separators) > 1:
                        final_chunks.extend(self._split_text(doc, separators[1:]))
                    else:
                        final_chunks.append({"text": doc})
                overlap_docs = []
                overlap_length = 0
                for d in reversed(current_doc):
                    if overlap_length + len(d) <= self.chunk_overlap:
                        overlap_docs.insert(0, d)
                        overlap_length += len(d)
                    else:
                        break
                current_doc = overlap_docs + [split]
                current_length = sum(len(d) for d in current_doc) + len(separator) * (len(current_doc) - 1)
        if current_doc:
            doc = separator.join(current_doc)
            if len(doc) > self.chunk_size and len(separators) > 1:
                final_chunks.extend(self._split_text(doc, separators[1:]))
            else:
                final_chunks.append({"text": doc})
        return final_chunks
